class HttpPaymentGateway implements PaymentGateway {
  final PaymentConfig config;
  final HttpClient _client = HttpClient();

  HttpPaymentGateway(this.config);

  Uri _uri(String path) {
    final base = config.backendBaseUrl;
    if (base == null || base.isEmpty) {
      throw StateError('backendBaseUrl is required for gateway operations');
    }
    return Uri.parse(base.endsWith('/') ? '$base${path.startsWith('/') ? path.substring(1) : path}' : '$base${path.startsWith('/') ? path : '/$path'}');
  }

  Map<String, String> _headers() => {
        'Content-Type': 'application/json',
        if (config.authToken != null && config.authToken!.isNotEmpty) 'Authorization': 'Bearer ${config.authToken}',
      };

  @override
  Future<WalletResult> processWalletPayment(WalletRequest request) async {
    try {
      final req = await _client.postUrl(_uri('/payments/wallet'));
      _headers().forEach(req.headers.set);
      req.write(jsonEncode({
        'walletType': request.walletType,
        'amount': request.amount,
        'currencyCode': request.currencyCode,
        'merchantId': request.merchantId,
        'countryCode': request.countryCode,
        'metadata': request.metadata,
        'env': config.environment.name,
        'gatewayMetadata': config.gatewayMetadata,
      }));
      final res = await req.close();
      final body = await utf8.decoder.bind(res).join();
      final decoded = body.isNotEmpty ? jsonDecode(body) as Map<String, dynamic> : <String, dynamic>{};
      final ok = res.statusCode >= 200 && res.statusCode < 300;
      return WalletResult(
        success: ok,
        token: decoded['token']?.toString(),
        errorCode: ok ? null : decoded['errorCode']?.toString(),
        errorMessage: ok ? null : decoded['errorMessage']?.toString() ?? 'Wallet payment failed',
        payload: decoded,
      );
    } catch (e) {
      return WalletResult(success: false, errorCode: 'network_error', errorMessage: e.toString());
    }
  }

  @override
  Future<bool> verifyTransaction({
    required String transactionId,
    required String productId,
    required String receiptOrToken,
    required String platform,
  }) async {
    try {
      final req = await _client.postUrl(_uri('/payments/verify'));
      _headers().forEach(req.headers.set);
      req.write(jsonEncode({
        'transactionId': transactionId,
        'productId': productId,
        'receiptOrToken': receiptOrToken,
        'platform': platform,
        'env': config.environment.name,
      }));
      final res = await req.close();
      return res.statusCode >= 200 && res.statusCode < 300;
    } catch (_) {
      return false;
    }
  }

  @override
  Future<void> logEvent(String name, Map<String, dynamic> data) async {
    if (!config.enableLogging) return;
    try {
      final req = await _client.postUrl(_uri('/payments/events'));
      _headers().forEach(req.headers.set);
      req.write(jsonEncode({'name': name, 'data': data, 'ts': DateTime.now().toUtc().toIso8601String()}));
      await req.close();
    } catch (_) {}
  }
}

class PaymentService {
  final PaymentConfig config;
  final PaymentGateway gateway;
  final InAppPurchase _iap = InAppPurchase.instance;
  final StreamController<PaymentResult> _resultController = StreamController<PaymentResult>.broadcast();
  final StreamController<PaymentStatus> _statusController = StreamController<PaymentStatus>.broadcast();
  final Map<String, ProductDetails> _productDetails = {};
  final Map<String, PaymentProduct> _products = {};
  StreamSubscription<List<PurchaseDetails>>? _purchaseSub;
  PaymentStatus _status = PaymentStatus.idle;
  bool _initialized = false;

  PaymentService({
    required this.config,
    required this.gateway,
  });

  Stream<PaymentResult> get results => _resultController.stream;
  Stream<PaymentStatus> get status => _statusController.stream;
  PaymentStatus get currentStatus => _status;
  bool get isInitialized => _initialized;

  void _emitStatus(PaymentStatus status) {
    _status = status;
    if (!_statusController.isClosed) _statusController.add(status);
  }

  void _emitResult(PaymentResult result) {
    if (!_resultController.isClosed) _resultController.add(result);
  }

  Future<void> initialize() async {
    if (_initialized) return;
    _emitStatus(PaymentStatus.initializing);

    final available = await _iap.isAvailable();
    if (!available) {
      _emitStatus(PaymentStatus.unavailable);
      _emitResult(const PaymentResult(status: PaymentStatus.unavailable, errorCode: 'iap_unavailable', errorMessage: 'In-app purchases unavailable'));
      return;
    }

    if (Platform.isIOS) {
      final iosAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosAddition.setDelegate(_StoreKitPaymentQueueDelegate());
    }

    _purchaseSub = _iap.purchaseStream.listen(_onPurchaseUpdated, onError: (Object error) {
      _emitStatus(PaymentStatus.failed);
      _emitResult(PaymentResult(status: PaymentStatus.failed, errorCode: 'purchase_stream_error', errorMessage: error.toString()));
    });

    _initialized = true;
    _emitStatus(PaymentStatus.ready);
  }

  Future<List<PaymentProduct>> loadProducts(Set<String> productIds, {Map<String, PaymentProductType> types = const {}}) async {
    if (!_initialized) await initialize();
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      _emitStatus(PaymentStatus.failed);
      _emitResult(PaymentResult(status: PaymentStatus.failed, errorCode: response.error!.code, errorMessage: response.error!.message));
      return const [];
    }

    _productDetails
      ..clear()
      ..addEntries(response.productDetails.map((e) => MapEntry(e.id, e)));

    final loaded = response.productDetails.map((pd) {
      final type = types[pd.id] ?? PaymentProductType.nonConsumable;
      final product = PaymentProduct(
        id: pd.id,
        title: pd.title,
        description: pd.description,
        price: pd.price,
        currencyCode: pd.currencyCode,
        type: type,
        rawPrice: pd.rawPrice.toString(),
        locale: pd.currencyCode,
      );
      _products[pd.id] = product;
      return product;
    }).toList(growable: false);

    return loaded;
  }

  Future<PaymentResult> purchaseProduct(String productId, {bool consumable = false}) async {
    if (!_initialized) await initialize();
    final details = _productDetails[productId];
    if (details == null) {
      return const PaymentResult(status: PaymentStatus.failed, errorCode: 'product_not_loaded', errorMessage: 'Product details not loaded');
    }

    _emitStatus(PaymentStatus.purchasing);
    final param = PurchaseParam(productDetails: details);
    final started = consumable
        ? await _iap.buyConsumable(purchaseParam: param, autoConsume: config.autoConsumeAndroidPurchases)
        : await _iap.buyNonConsumable(purchaseParam: param);

    if (!started) {
      _emitStatus(PaymentStatus.failed);
      return const PaymentResult(status: PaymentStatus.failed, errorCode: 'purchase_start_failed', errorMessage: 'Unable to start purchase');
    }

    return const PaymentResult(status: PaymentStatus.pending);
  }

  Future<void> restorePurchases() async {
    if (!_initialized) await initialize();
    await _iap.restorePurchases();
  }

  Future<WalletResult> payWithWallet(WalletRequest request) async {
    if (!config.supportedWallets.contains(request.walletType)) {
      return const WalletResult(success: false, errorCode: 'wallet_not_supported', errorMessage: 'Wallet not supported');
    }
    return gateway.processWalletPayment(request);
  }

  Future<void> dispose() async {
    await _purchaseSub?.cancel();
    await _resultController.close();
    await _statusController.close();
    if (Platform.isIOS) {
      final iosAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosAddition.setDelegate(null);
    }
  }

  Future<void> _onPurchaseUpdated(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      switch (purchase.status) {
        case PurchaseStatus.pending:
          _emitStatus(PaymentStatus.pending);
          _emitResult(PaymentResult(
            status: PaymentStatus.pending,
            transactionId: purchase.purchaseID,
            productId: purchase.productID,
            payload: _purchasePayload(purchase),
          ));
          break;
        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          final verified = await _verifyAndFinalize(purchase);
          if (verified) {
            _emitStatus(purchase.status == PurchaseStatus.restored ? PaymentStatus.restored : PaymentStatus.succeeded);
            _emitResult(PaymentResult(
              status: purchase.status == PurchaseStatus.restored ? PaymentStatus.restored : PaymentStatus.succeeded,
              transactionId: purchase.purchaseID,
              productId: purchase.productID,
              payload: _purchasePayload(purchase),
            ));
          } else {
            _emitStatus(PaymentStatus.failed);
            _emitResult(PaymentResult(
              status: PaymentStatus.failed,
              transactionId: purchase.purchaseID,
              productId: purchase.productID,
              errorCode: 'verification_failed',
              errorMessage: 'Transaction verification failed',
              payload: _purchasePayload(purchase),
            ));
          }
          break;
        case PurchaseStatus.error:
          _emitStatus(PaymentStatus.failed);
          _emitResult(PaymentResult(
            status: PaymentStatus.failed,
            transactionId: purchase.purchaseID,
            productId: purchase.productID,
            errorCode: purchase.error?.code,
            errorMessage: purchase.error?.message,
            payload: _purchasePayload(purchase),
          ));
          break;
        case PurchaseStatus.canceled:
          _emitStatus(PaymentStatus.canceled);
          _emitResult(PaymentResult(
            status: PaymentStatus.canceled,
            transactionId: purchase.purchaseID,
            productId: purchase.productID,
            errorCode: 'canceled',
            errorMessage: 'Purchase canceled',
            payload: _purchasePayload(purchase),
          ));
          break;
        case PurchaseStatus.pendingDeferred:
          _emitStatus(PaymentStatus.pending);
          break;
      }

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }
  }

  Future<bool> _verifyAndFinalize(PurchaseDetails purchase) async {
    if (!config.requireServerVerification) return true;
    final receipt = _extractReceipt(purchase);
    if (receipt == null || receipt.isEmpty) return false;
    final platform = Platform.isIOS ? 'ios' : 'android';
    return gateway.verifyTransaction(
      transactionId: purchase.purchaseID ?? purchase.productID,
      productId: purchase.productID,
      receiptOrToken: receipt,
      platform: platform,
    );
  }

  String? _extractReceipt(PurchaseDetails purchase) {
    final verificationData = purchase.verificationData;
    if (verificationData.serverVerificationData.isNotEmpty) return verificationData.serverVerificationData;
    if (verificationData.localVerificationData.isNotEmpty) return verificationData.localVerificationData;
    return null;
  }

  Map<String, dynamic> _purchasePayload(PurchaseDetails purchase) => {
        'productId': purchase.productID,
        'purchaseId': purchase.purchaseID,
        'status': purchase.status.name,
        'pendingCompletePurchase': purchase.pendingCompletePurchase,
        'verificationData': {
          'source': purchase.verificationData.source,
          'serverVerificationData': purchase.verificationData.serverVerificationData,
          'localVerificationData': purchase.verificationData.localVerificationData,
        },
      };
}

