class PaymentModule {
  final PaymentService service;

  PaymentModule._(this.service);

  static Future<PaymentModule> create(PaymentConfig config) async {
    final gateway = HttpPaymentGateway(config);
    final service = PaymentService(config: config, gateway: gateway);
    await service.initialize();
    return PaymentModule._(service);
  }
}

class PaymentRepository {
  final PaymentService service;
  PaymentRepository(this.service);

  Stream<PaymentResult> get results => service.results;
  Stream<PaymentStatus> get status => service.status;

  Future<List<PaymentProduct>> loadCatalog(List<String> ids, {Map<String, PaymentProductType> types = const {}}) {
    return service.loadProducts(ids.toSet(), types: types);
  }

  Future<PaymentResult> buy(String productId, {bool consumable = false}) {
    return service.purchaseProduct(productId, consumable: consumable);
  }

  Future<void> restore() => service.restorePurchases();

  Future<WalletResult> walletPay(WalletRequest request) => service.payWithWallet(request);

  Future<void> dispose() => service.dispose();
}

class PaymentSecurity {
  static String redact(String input) {
    if (input.isEmpty) return input;
    if (input.length <= 8) return '****';
    return '${input.substring(0, 4)}****${input.substring(input.length - 4)}';
  }

  static Map<String, dynamic> sanitizePayload(Map<String, dynamic> payload) {
    final copy = Map<String, dynamic>.from(payload);
    for (final key in ['token', 'receipt', 'serverVerificationData', 'localVerificationData', 'authToken']) {
      if (copy.containsKey(key) && copy[key] is String) {
        copy[key] = redact(copy[key] as String);
      }
    }
    return copy;
  }
}

class PaymentLogger {
  final bool enabled;
  PaymentLogger(this.enabled);

  void log(String message, [Map<String, dynamic> data = const {}]) {
    if (!enabled) return;
    debugPrint('[Payment] $message ${jsonEncode(PaymentSecurity.sanitizePayload(data))}');
  }
}

